mapper.update:
update store_amend
set state = #{state}

    ,cause = #{cause}

where id = #{id}

mapper.select:
SELECT id,dept_id,name,address FROM store


        AND name LIKE CONCAT('%',#{name},'%')


        AND dept_id IN

            #{deptId}



ORDER BY id
LIMIT #{skip},#{pageSize}

select sm.id,sm.material_id,m.name,mc.name as className,sm.sum from store_material sm join material m on sm.material_id = m.id left join material_class mc on m.class_id = mc.id
sm.store_id = #{id}
AND m.name LIKE CONCAT('%',#{name},'%')
AND mc.name like CONCAT('%',#{className},'%')
limit #{skip},#{pageSize}

select id, operation, num, create_time,source_type, source_id
from store_material_log

    repertory_id = #{id}

        AND operation = #{operation}


        AND create_time >= #{startDate}


        AND create_time <= #{endDate}



    AND id < #{lastId}

ORDER BY id DESC
LIMIT #{pageSize}

select id from store_material_log

    repertory_id = #{id}

        AND operation = #{operation}


        AND create_time >= #{startDate}


        AND create_time <= #{endDate}


ORDER BY id ASC
LIMIT 1

SELECT COUNT(*) FROM enquiry join dept on enquiry.dept_id = dept.id


        AND enquiry.applicant_id = #{applicantId}


        AND enquiry.dept_id IN

            #{deptId}



        AND enquiry.no = #{no}


        AND enquiry.state = #{state}


        AND dept.name like concat('%',#{dept},'%')


        AND enquiry.amount >= #{minMoney}


        AND enquiry.amount <= #{maxMoney}

SELECT enquiry.id,outbound.id as outboundId, enquiry.amount, enquiry.state, dept.name as dept FROM enquiry
join dept on enquiry.dept_id = dept.id
left join outbound on outbound.enquiry_id = enquiry.id


        AND enquiry.applicant_id = #{applicantId}


        AND enquiry.dept_id IN

            #{deptId}



        AND enquiry.no = #{no}


        AND enquiry.state = #{state}


        AND dept.name like concat('%',#{dept},'%')


        AND enquiry.amount >= #{minMoney}


        AND enquiry.amount <= #{maxMoney}


limit #{skip},#{pageSize}

SELECT o.id,o.no,ui.name as stocker,s.name as store,d.name as dept,o.state, o.update_time FROM outbound o join user_info ui on o.stocker_id = ui.user_id join store s on o.store_out_id = s.id join dept d on s.dept_id = d.id
AND o.store_out_id IN
#{storeId}
AND o.no like concat(#{no},'%')
AND ui.name like concat('%',#{stocker},'%')
AND s.name like concat('%',#{store},'%')
AND d.name like concat('%',#{dept},'%')
AND o.state = #{state}
limit #{skip},#{pageSize}

SELECT sml.repertory_id,sml.source_type, sml.source_id,sm.store_id, sm.material_id, sml.num
FROM store_material_log sml
JOIN store_material sm ON sml.repertory_id = sm.id


        AND sml.source_type = #{sourceType}


        AND sml.source_id IN

            #{sourceId}



        AND sml.operation = #{operation}


        AND sml.create_time >= #{startDate}


        AND sml.create_time <= #{endDate}

SELECT COUNT(*) FROM store_amend sa join store s on sa.store_id = s.id join dept d on s.dept_id = d.id
store_id IN
#{storeId}
AND sa.state = #{state}
AND d.name like concat('%',#{dept},'%')

SELECT sa.id,d.name as deptName,ui.name as repertory ,sa.state,sa.create_time FROM store_amend sa
join store s on sa.store_id = s.id
join dept d on s.dept_id = d.id
join user_info ui on sa.applicant_id = ui.user_id


        store_id IN

            #{storeId}



        AND sa.state = #{state}


        AND d.name like concat('%',#{dept},'%')


limit #{skip},#{pageSize}

SELECT id,name FROM store
WHERE id IN

    #{storeId}
